import{_ as a,o as i,c as e,a0 as n}from"./chunks/framework.CWk8AOcY.js";const k=JSON.parse('{"title":"开发环境（QEMU 虚拟机）","description":"","frontmatter":{},"headers":[],"relativePath":"guide/dev-environment.md","filePath":"zh/guide/dev-environment.md"}'),t={name:"guide/dev-environment.md"};function l(d,s,h,p,o,c){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="开发环境-qemu-虚拟机" tabindex="-1">开发环境（QEMU 虚拟机） <a class="header-anchor" href="#开发环境-qemu-虚拟机" aria-label="Permalink to &quot;开发环境（QEMU 虚拟机）&quot;">​</a></h1><p>如果你没有一台独占的 bare-metal 服务器，只有一台笔记本或者云主机，但仍 然想体验或开发 Cube Sandbox，可以直接在宿主机里起一台<strong>一次性的 OpenCloudOS 9 虚机</strong>，把 Cube Sandbox 装在虚机里跑。</p><p>仓库根目录下的 <code>dev-env/</code> 已经把整个流程脚本化了：一次性的镜像准备、 虚机启动、自动登录三件套。</p><p>只需要三条命令，你就能获得一个CubeSandbox体验环境。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>本文的开发环境脚本需要跑在下面这三种宿主机之一：</p><ul><li><strong>Windows 上的 WSL 2</strong>（需要 Windows 11 22H2+，并在 WSL 里启用嵌套虚拟化）</li><li><strong>Linux 物理机</strong></li><li><strong>已开启嵌套虚拟化的 Linux 虚拟机</strong>（云主机 / 本地虚机均可）</li></ul><p>三者共同要求：宿主机能正常使用 KVM —— <code>/dev/kvm</code> 存在且可读写。</p><p>Cube Sandbox 在虚机内还要继续用 KVM 起 MicroVM，所以宿主机必须支持 嵌套虚拟化，否则虚机里拿不到可用的 <code>/dev/kvm</code>，沙箱创建会失败。</p><p>更细的软件依赖、KVM 自检与启用方法见下文『宿主机自检』章节。</p><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><p>先克隆仓库，进入 <code>dev-env/</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/tencentcloud/CubeSandbox.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CubeSandbox/dev-env</span></span></code></pre></div><p>一共三条命令。前两条在同一个终端执行，第三条在<strong>新终端</strong>里执行。</p><h3 id="第一步-准备镜像-仅首次" tabindex="-1">第一步：准备镜像（仅首次） <a class="header-anchor" href="#第一步-准备镜像-仅首次" aria-label="Permalink to &quot;第一步：准备镜像（仅首次）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./prepare_image.sh</span></span></code></pre></div><p>脚本会从腾讯镜像站下载官方 OpenCloudOS 9 qcow2，并完成初始化操作。</p><p>一个镜像只需要跑一次——除非你删掉了 <code>.workdir/</code>，或者想重新生成一份 干净镜像。</p><h3 id="第二步-启动虚机" tabindex="-1">第二步：启动虚机 <a class="header-anchor" href="#第二步-启动虚机" aria-label="Permalink to &quot;第二步：启动虚机&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./run_vm.sh</span></span></code></pre></div><p>QEMU 串口会挂在当前终端。想关机按 <code>Ctrl+a</code> 然后 <code>x</code>。</p><h3 id="第三步-登录虚机-新开一个终端" tabindex="-1">第三步：登录虚机（新开一个终端） <a class="header-anchor" href="#第三步-登录虚机-新开一个终端" aria-label="Permalink to &quot;第三步：登录虚机（新开一个终端）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./login.sh</span></span></code></pre></div><p><code>login.sh</code> 会登录到虚拟机内（root 权限），因为 Cube Sandbox 的部署需要 在 root 下进行。</p><h3 id="在虚机内安装-cube-sandbox" tabindex="-1">在虚机内安装 Cube Sandbox <a class="header-anchor" href="#在虚机内安装-cube-sandbox" aria-label="Permalink to &quot;在虚机内安装 Cube Sandbox&quot;">​</a></h3><p>进入 root shell 之后，直接执行标准的一键安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/tencentcloud/CubeSandbox/raw/master/deploy/one-click/online-install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">国内环境建议走腾讯云镜像</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://cnb.cool/CubeSandbox/CubeSandbox/-/git/raw/master/deploy/one-click/online-install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> MIRROR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div></div><p>安装完成后按常规 <a href="./quickstart.html">快速开始</a> 在虚拟机内创建模板、跑第一个沙箱即可。</p><hr><p>以下是对上面流程的补充说明与排查手册，正常情况下可以先跳过。</p><h2 id="适用场景与边界" tabindex="-1">适用场景与边界 <a class="header-anchor" href="#适用场景与边界" aria-label="Permalink to &quot;适用场景与边界&quot;">​</a></h2><ul><li>想要一个干净的 OpenCloudOS 9 环境快速体验 Cube Sandbox。</li><li>只有笔记本 / 云主机（已开启 KVM 和 nested virtualization），没有物理服务器。</li><li>想在虚机里迭代 Cube Sandbox，不污染宿主机。</li></ul><div class="warning custom-block"><p class="custom-block-title">不是生产部署方式</p><p>这里明确是<strong>开发 / 体验</strong>环境。生产部署请走 <a href="./quickstart.html">快速开始</a> 或 <a href="./multi-node-deploy.html">多机集群部署</a>，在 bare-metal 机器上执行。</p></div><h2 id="宿主机自检" tabindex="-1">宿主机自检 <a class="header-anchor" href="#宿主机自检" aria-label="Permalink to &quot;宿主机自检&quot;">​</a></h2><p>宿主机需要的软件依赖：</p><ul><li>Linux x86_64，已启用 KVM（存在 <code>/dev/kvm</code>）</li><li>开启了 nested virtualization</li><li>已安装 <code>qemu-system-x86_64</code>、<code>qemu-img</code>、<code>curl</code>、<code>ssh</code>、<code>scp</code>、<code>setsid</code></li></ul><p>快速自检：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/kvm</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Intel</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/module/kvm_intel/parameters/nested</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># AMD</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/module/kvm_amd/parameters/nested</span></span></code></pre></div><p>如果 <code>nested</code> 返回 <code>N</code> 或 <code>0</code>，请先在宿主机开启它。以 Intel 为例：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;options kvm_intel nested=1&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tee</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/modprobe.d/kvm.conf</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modprobe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kvm_intel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modprobe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kvm_intel</span></span></code></pre></div><h2 id="宿主机-↔-虚机端口映射" tabindex="-1">宿主机 ↔ 虚机端口映射 <a class="header-anchor" href="#宿主机-↔-虚机端口映射" aria-label="Permalink to &quot;宿主机 ↔ 虚机端口映射&quot;">​</a></h2><p><code>run_vm.sh</code> 启动时会自动配置下面这两条转发：</p><table tabindex="0"><thead><tr><th>宿主机</th><th>虚机</th><th>用途</th></tr></thead><tbody><tr><td><code>127.0.0.1:10022</code></td><td><code>:22</code></td><td>虚机 SSH</td></tr><tr><td><code>127.0.0.1:13000</code></td><td><code>:3000</code></td><td>Cube Sandbox 兼容 E2B 的 API</td></tr></tbody></table><h2 id="prepare-image-sh-在虚机内做了什么" tabindex="-1">prepare_image.sh 在虚机内做了什么 <a class="header-anchor" href="#prepare-image-sh-在虚机内做了什么" aria-label="Permalink to &quot;prepare_image.sh 在虚机内做了什么&quot;">​</a></h2><ul><li>把根分区和根文件系统撑满整个 100 GB 磁盘。</li><li>把 SELinux 切成 <code>permissive</code>（运行时 + <code>/etc/selinux/config</code>）。 Cube Sandbox 的 MySQL 容器会把 <code>/docker-entrypoint-initdb.d</code> 以 bind mount 方式挂进容器，如果 SELinux enforcing 加上 <code>container-selinux</code> 策略生效，容器进程会被拒绝，mysql 容器反复重启。</li><li>把 <code>/usr/local/{sbin,bin}</code> 加到登录 shell 的 <code>PATH</code> 和 sudo 的 <code>secure_path</code>，这样无论登录 shell 还是 <code>sudo cmd</code>，都能直接调用 <code>cubemastercli</code> 等二进制。</li><li>往 <code>/etc/profile.d/cubesandbox-banner.sh</code> 写入登录 banner，之后每次 登录都会看到 <code>Welcome to the Cube Sandbox development environment!</code>。</li></ul><h2 id="常用环境变量" tabindex="-1">常用环境变量 <a class="header-anchor" href="#常用环境变量" aria-label="Permalink to &quot;常用环境变量&quot;">​</a></h2><p>三个脚本都支持用环境变量覆盖默认值：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 本次只下载并扩容 qcow2，不跑 guest 内的自动扩容。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AUTO_BOOT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./prepare_image.sh</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 启动虚机时换更多资源 / 换 Cube API 端口。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VM_MEMORY_MB</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">16384</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> VM_CPUS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CUBE_API_PORT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">23000</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./run_vm.sh</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 不强制要求 nested KVM（只想把系统起来看看，不跑沙箱）。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">REQUIRE_NESTED_KVM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./run_vm.sh</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 登录时留在普通用户，不切 root。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">LOGIN_AS_ROOT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./login.sh</span></span></code></pre></div><p><code>run_vm.sh</code> 的默认配置：4 CPU、8192 MB 内存，SSH 转发 <code>127.0.0.1:10022</code>，Cube API 转发 <code>127.0.0.1:13000</code>（虚机内 <code>:3000</code>）。</p><h2 id="重置-清理" tabindex="-1">重置 / 清理 <a class="header-anchor" href="#重置-清理" aria-label="Permalink to &quot;重置 / 清理&quot;">​</a></h2><ul><li>想重置虚机状态：先停掉 <code>run_vm.sh</code>，删掉 <code>dev-env/.workdir/</code> 目录， 再重跑 <code>./prepare_image.sh</code>。</li><li>开发环境本身就是一次性的。一旦虚机里装的东西乱了，重建即可。</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能原因</th><th>解决方法</th></tr></thead><tbody><tr><td>虚机内没有 <code>/dev/kvm</code></td><td>宿主机未开启 nested KVM</td><td>在宿主机启用 nested virtualization 后重启虚机</td></tr><tr><td><code>./login.sh</code> 连不上</td><td>虚机还没启动，或宿主机 <code>10022</code> 端口被占</td><td>确认 <code>./run_vm.sh</code> 还在运行，或通过 <code>SSH_PORT</code> 换端口</td></tr><tr><td><code>cube-sandbox-mysql</code> 反复重启且报 <code>Permission denied</code></td><td>虚机里 SELinux 还是 enforcing</td><td>重跑 <code>./prepare_image.sh</code>；或在虚机里执行 <code>setenforce 0 &amp;&amp; sed -i &#39;s/^SELINUX=enforcing/SELINUX=permissive/&#39; /etc/selinux/config &amp;&amp; docker restart cube-sandbox-mysql</code></td></tr><tr><td><code>df -h /</code> 仍然很小</td><td>虚机内自动扩容没走完</td><td>看 <code>.workdir/qemu-serial.log</code>，再把 <code>internal/grow_rootfs.sh</code> scp 进去手动跑一次</td></tr><tr><td>宿主机 <code>13000</code> 端口被占</td><td>本机有别的服务</td><td>用 <code>CUBE_API_PORT=23000 ./run_vm.sh</code>，并相应调整 <code>E2B_API_URL</code></td></tr></tbody></table><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dev-env/</span></span>
<span class="line"><span>├── prepare_image.sh   # 一次性：下载 + 扩容 qcow2 + 虚机内初始化</span></span>
<span class="line"><span>├── run_vm.sh          # 日常：启动虚机</span></span>
<span class="line"><span>├── login.sh           # 日常：SSH 登录并切到 root</span></span>
<span class="line"><span>├── internal/          # prepare_image.sh 自动传进虚机执行的辅助脚本</span></span>
<span class="line"><span>│   ├── grow_rootfs.sh</span></span>
<span class="line"><span>│   ├── setup_selinux.sh</span></span>
<span class="line"><span>│   ├── setup_path.sh</span></span>
<span class="line"><span>│   └── setup_banner.sh</span></span>
<span class="line"><span>├── README.md</span></span>
<span class="line"><span>└── README_zh.md</span></span></code></pre></div><p>短版说明见仓库的 <a href="https://github.com/tencentcloud/CubeSandbox/tree/master/dev-env/README_zh.md" target="_blank" rel="noreferrer"><code>dev-env/README_zh.md</code></a>。</p>`,57)])])}const u=a(t,[["render",l]]);export{k as __pageData,u as default};
